mapper.update:
UPDATE balance_bucket b
SET
    available_balance = b.available_balance + v.available_delta,
    frozen_balance = b.frozen_balance + v.frozen_delta,
    total_balance = b.total_balance + v.total_delta,
    withdraw_amount = COALESCE(b.withdraw_amount, 0) + v.withdraw_delta,
    update_time = #{updateTime}
FROM (
    VALUES

        (
            #{item.bucketNo},
            #{item.availableDelta},
            #{item.frozenDelta},
            #{item.totalDelta},
            #{item.withdrawDelta}
        )

) AS v(bucket_no, available_delta, frozen_delta, total_delta, withdraw_delta)
WHERE b.user_id = #{userId}
  AND b.currency = #{currency}
  AND b.bucket_no = v.bucket_no

UPDATE balance_bucket
SET
    available_balance = available_balance - #{amount},
    frozen_balance = frozen_balance + #{amount},
    update_time = #{updateTime}
WHERE user_id = #{userId}
  AND currency = #{currency}
  AND bucket_no = #{bucketNo}
  AND available_balance >= #{amount}

UPDATE balance_bucket
SET
    frozen_balance = COALESCE(frozen_balance, 0) - #{amount},
    available_balance = COALESCE(available_balance, 0) + #{amount},
    update_time = #{updateTime}
WHERE user_id = #{userId}
  AND currency = #{currency}
  AND bucket_no = #{bucketNo}
  AND frozen_balance >= #{amount}

UPDATE balance_bucket
SET
    available_balance = available_balance + #{amount},
    total_balance = total_balance + #{amount},
    update_time = #{now}
WHERE user_id = #{userId}
  AND currency = #{currency}
  AND bucket_no = #{bucketNo}
  AND (#{amount} >= 0 OR available_balance >= -#{amount})

UPDATE balance_bucket
SET
    available_balance = available_balance - #{amount},
    frozen_balance = frozen_balance + #{amount},
    update_time = #{now}
WHERE user_id = #{userId}
  AND currency = #{currency}
  AND bucket_no = #{bucketNo}
  AND available_balance >= #{amount}

UPDATE balance_bucket
SET
    frozen_balance = frozen_balance - #{amount},
    withdraw_amount = COALESCE(withdraw_amount, 0) + #{amount},
    update_time = #{now}
WHERE user_id = #{userId}
  AND currency = #{currency}
  AND bucket_no = #{bucketNo}
  AND frozen_balance >= #{amount}

UPDATE balance_bucket
SET
    frozen_balance = frozen_balance - #{amount},
    available_balance = available_balance + #{amount},
    update_time = #{now}
WHERE user_id = #{userId}
  AND currency = #{currency}
  AND bucket_no = #{bucketNo}
  AND frozen_balance >= #{amount}

UPDATE balance_bucket
SET
    frozen_balance = frozen_balance - #{amount},
    total_balance = total_balance - #{amount},
    update_time = #{now}
WHERE user_id = #{userId}
  AND currency = #{currency}
  AND bucket_no = #{bucketNo}
  AND frozen_balance >= #{amount}
